import{_ as t,o,c as a,ae as e}from"./chunks/framework.Dzr56EFm.js";const d=JSON.parse('{"title":"大厂战略 - 2026-03-17","description":"","frontmatter":{"date":"2026-03-17T00:00:00.000Z","category":"BigTech"},"headers":[],"relativePath":"daily/2026-03-17-bigtech.md","filePath":"daily/2026-03-17-bigtech.md"}'),n={name:"daily/2026-03-17-bigtech.md"};function s(g,r,p,i,l,h){return o(),a("div",null,[...r[0]||(r[0]=[e('<h1 id="大厂战略-2026-03-17" tabindex="-1">大厂战略 - 2026-03-17 <a class="header-anchor" href="#大厂战略-2026-03-17" aria-label="Permalink to &quot;大厂战略 - 2026-03-17&quot;">​</a></h1><blockquote><p>OpenAI、Google、Apple、Microsoft、Meta、Amazon战略</p></blockquote><h2 id="今日概览" tabindex="-1">今日概览 <a class="header-anchor" href="#今日概览" aria-label="Permalink to &quot;今日概览&quot;">​</a></h2><p>今日大厂战略领域主要动态包括微软提供的AI战略规划框架、谷歌提出的2026年营销AI策略、苹果探讨AI推理与规划的研讨会，以及微软为政府领导者提供的国家AI战略构建指导。最值得关注的是谷歌的营销AI策略和微软的AI战略规划框架，它们分别针对营销和企业系统化规划提供了实用指导。</p><hr><h3 id="_1-制定你的ai战略-云采用框架-微软学习" tabindex="-1">1. 制定你的AI战略 - 云采用框架 - 微软学习 <a class="header-anchor" href="#_1-制定你的ai战略-云采用框架-微软学习" aria-label="Permalink to &quot;1. 制定你的AI战略 - 云采用框架 - 微软学习&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://learn.microsoft.com/en-us/azure/cloud-adoption-framework/scenarios/ai/strategy" target="_blank" rel="noreferrer">Create your AI strategy - Cloud Adoption Framework - Microsoft Learn</a></p><p><strong>一句话摘要</strong>: 微软提供了一个AI战略规划框架，帮助企业系统化地规划和实施AI。</p><p><strong>能解决什么问题</strong>: 解决企业在规划和实施AI时面临的结构化和规模化挑战。</p><p><strong>产品应用</strong>: 适用于各种规模的组织，包括初创公司、中小企业、大型企业和公共部门机构。</p><p><strong>示例场景</strong>: 虚构公司Contoso使用该框架来预测业务数据和优化产品开发。</p><hr><h3 id="_2-ai战略路线图-导航价值创造的各个阶段" tabindex="-1">2. AI战略路线图：导航价值创造的各个阶段 <a class="header-anchor" href="#_2-ai战略路线图-导航价值创造的各个阶段" aria-label="Permalink to &quot;2. AI战略路线图：导航价值创造的各个阶段&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.microsoft.com/en-us/microsoft-cloud/blog/2024/04/03/the-ai-strategy-roadmap-navigating-the-stages-of-value-creation/" target="_blank" rel="noreferrer">The AI Strategy Roadmap: Navigating the stages of value creation</a></p><p><strong>一句话摘要</strong>: 为不同组织提供实用的AI实施指导</p><p><strong>能解决什么问题</strong>: 缺乏与组织业务战略相一致的AI实施路线图</p><p><strong>产品应用</strong>: 可以应用到实际产品中，根据组织准备阶段和需求定制AI战略</p><p><strong>示例场景</strong>: 教育领域使用AI改善教学和学习体验</p><hr><h3 id="_3-广告解码-2026年掌握营销的3大ai策略-谷歌" tabindex="-1">3. 广告解码：2026年掌握营销的3大AI策略 - 谷歌 <a class="header-anchor" href="#_3-广告解码-2026年掌握营销的3大ai策略-谷歌" aria-label="Permalink to &quot;3. 广告解码：2026年掌握营销的3大AI策略 - 谷歌&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://blog.google/products/ads-commerce/ai-strategies-master-marketing-2026/" target="_blank" rel="noreferrer">Ads Decoded: 3 AI strategies to master marketing in 2026 - Google</a></p><p><strong>一句话摘要</strong>: 谷歌提出三大AI策略，助力2026年营销发展。</p><p><strong>能解决什么问题</strong>: 解决搜索行为变化带来的营销适应性问题。</p><p><strong>产品应用</strong>: 适用于实际产品，通过AI优化广告投放和内容创作。</p><p><strong>示例场景</strong>: 使用AI工具在YouTube上精准定位高参与度用户。</p><hr><h3 id="_4-苹果2025年推理与规划研讨会" tabindex="-1">4. 苹果2025年推理与规划研讨会 <a class="header-anchor" href="#_4-苹果2025年推理与规划研讨会" aria-label="Permalink to &quot;4. 苹果2025年推理与规划研讨会&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://machinelearning.apple.com/updates/reasoning-workshop-2025" target="_blank" rel="noreferrer">Apple Workshop on Reasoning and Planning 2025</a></p><p><strong>一句话摘要</strong>: 苹果举办研讨会，探讨AI推理与规划技术。</p><p><strong>能解决什么问题</strong>: 提高AI系统的独立操作能力和复杂任务处理。</p><p><strong>产品应用</strong>: 可应用于智能助手、自动驾驶等，提升决策和交互能力。</p><p><strong>示例场景</strong>: 智能助手根据指令完成复杂任务。</p><hr><h3 id="_5-赋能政府在人工智能时代领先-微软公共部门" tabindex="-1">5. 赋能政府在人工智能时代领先 - 微软公共部门 <a class="header-anchor" href="#_5-赋能政府在人工智能时代领先-微软公共部门" aria-label="Permalink to &quot;5. 赋能政府在人工智能时代领先 - 微软公共部门&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://wwps.microsoft.com/blog/national-strategic-framework-guide" target="_blank" rel="noreferrer">Enabling governments to lead in the AI era - Microsoft&#39;s Public Sector</a></p><p><strong>一句话摘要</strong>: 政府领导者可以构建国家AI战略，以提升经济、治理和公共服务。</p><p><strong>能解决什么问题</strong>: 如何利用AI提升国家经济表现和公共服务效率。</p><p><strong>产品应用</strong>: 可以应用到实际产品中，通过建立法规和标准来引导AI技术应用。</p><p><strong>示例场景</strong>: 利用AI改进金融监管，提高公共安全。</p><hr><h3 id="_6-ai战略路线图-微软行业云" tabindex="-1">6. AI战略路线图 - 微软行业云 <a class="header-anchor" href="#_6-ai战略路线图-微软行业云" aria-label="Permalink to &quot;6. AI战略路线图 - 微软行业云&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://info.microsoft.com/ww-landing-the-ai-strategy-roadmap.html" target="_blank" rel="noreferrer">AI Strategy Roadmap - Microsoft Industry Clouds</a></p><p><strong>一句话摘要</strong>: 构建基于成功IT领导者和商业决策者的见解的可扩展AI战略。</p><p><strong>能解决什么问题</strong>: 缺乏清晰的AI转型路线图和成功实践指导。</p><p><strong>产品应用</strong>: 适用于企业制定和实施AI战略，提升业务决策效率。</p><p><strong>示例场景</strong>: 企业利用AI战略路线图优化数据分析流程。</p><hr><h3 id="_7-扩展meta定制芯片以支持ai工作负载" tabindex="-1">7. 扩展Meta定制芯片以支持AI工作负载 <a class="header-anchor" href="#_7-扩展meta定制芯片以支持ai工作负载" aria-label="Permalink to &quot;7. 扩展Meta定制芯片以支持AI工作负载&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://about.fb.com/news/2026/03/expanding-metas-custom-silicon-to-power-our-ai-workloads/" target="_blank" rel="noreferrer">Expanding Meta&#39;s Custom Silicon to Power Our AI Workloads</a></p><p><strong>一句话摘要</strong>: Meta在两年内开发四代新芯片，提升计算、内存带宽和效率。</p><p><strong>能解决什么问题</strong>: 解决AI工作负载对高性能、高效率芯片的需求。</p><p><strong>产品应用</strong>: 可以应用到实际产品中，如排名、推荐训练和GenAI推理生产。</p><p><strong>示例场景</strong>: 用于推荐系统训练和AI推理的芯片部署。</p><hr><h3 id="_8-2026年ai七大趋势-微软预测人工智能的未来" tabindex="-1">8. 2026年AI七大趋势：微软预测人工智能的未来 <a class="header-anchor" href="#_8-2026年ai七大趋势-微软预测人工智能的未来" aria-label="Permalink to &quot;8. 2026年AI七大趋势：微软预测人工智能的未来&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://news.microsoft.com/source/emea/features/whats-next-in-ai-7-trends-2026/" target="_blank" rel="noreferrer">What&#39;s Next in AI? 7 Key Trends Shaping 2026 | Microsoft Source</a></p><p><strong>一句话摘要</strong>: AI将从工具转变为合作伙伴，与人类共同工作。</p><p><strong>能解决什么问题</strong>: 解决数据处理、内容生成和个性化问题，提高工作效率。</p><p><strong>产品应用</strong>: 可应用于全球营销活动，AI处理数据和内容，人类负责策略和创意。</p><p><strong>示例场景</strong>: 三人团队借助AI快速启动全球营销活动。</p><hr><h3 id="_9-我们的2026年负责任ai进展报告-谷歌" tabindex="-1">9. 我们的2026年负责任AI进展报告 - 谷歌 <a class="header-anchor" href="#_9-我们的2026年负责任ai进展报告-谷歌" aria-label="Permalink to &quot;9. 我们的2026年负责任AI进展报告 - 谷歌&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://blog.google/innovation-and-ai/products/responsible-ai-2026-report-ongoing-work/" target="_blank" rel="noreferrer">Our 2026 Responsible AI Progress Report - Google</a></p><p><strong>一句话摘要</strong>: 谷歌分享负责任AI发展的最新进展报告。</p><p><strong>能解决什么问题</strong>: 解决AI模型能力增强带来的风险测试和缓解问题。</p><p><strong>产品应用</strong>: 已嵌入产品开发和研究生命周期，通过多层治理实现。</p><p><strong>示例场景</strong>: 个性化多模态AI模型的风险检测和适应性调整。</p><hr><h3 id="_10-十月谷歌ai最新动态" tabindex="-1">10. 十月谷歌AI最新动态 <a class="header-anchor" href="#_10-十月谷歌ai最新动态" aria-label="Permalink to &quot;10. 十月谷歌AI最新动态&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://blog.google/innovation-and-ai/products/google-ai-updates-october-2025/" target="_blank" rel="noreferrer">The latest AI news we announced in October - Google</a></p><p><strong>一句话摘要</strong>: 谷歌推出Gemini Enterprise，推动AI在工作场所的应用。</p><p><strong>能解决什么问题</strong>: 帮助企业利用先进的AI模型，基于公司数据构建、部署AI代理。</p><p><strong>产品应用</strong>: 适用于需要AI解决方案的企业，如医疗保健和零售行业。</p><p><strong>示例场景</strong>: HCA Healthcare和Best Buy使用Gemini Enterprise提升效率。</p><hr>',75)])])}const A=t(n,[["render",s]]);export{d as __pageData,A as default};
